import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum RiskLevel {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH',
  CRITICAL = 'CRITICAL'
}

export interface Driver {
  id: string;
  name: string;
  impact: number; // 0-100 impact on the score
}

export interface RiskPillar {
  id: string;
  name: string;
  score: number; // 0-100
  trend: 'up' | 'down' | 'stable';
  trendValue: number;
  drivers: Driver[];
}

export interface EvidenceItem {
  id: string;
  type: 'PDF' | 'URL' | 'NEWS';
  name: string;
  date: string;
  status: 'processed' | 'processing' | 'error';
  tags: string[];
}

export interface Indicator {
  id: string;
  name: string;
  value: string | number;
  unit: string;
  confidence: number; // 0-100
  source: string;
  isOverridden: boolean;
  overrideReason?: string;
  lastUpdated: string;
}

export interface CompanyData {
  id: string;
  name: string;
  ticker: string;
  lei: string;
  sector: string;
  status: 'LIVE' | 'DRAFT' | 'REVIEW';
  lastUpdated: string;
  version: string;
  pillars: {
    sustainability: RiskPillar;
    pchi: RiskPillar;
    operational: RiskPillar;
    financial: RiskPillar;
  };
  indicators: Indicator[];
  evidence: EvidenceItem[];
}

import React from 'react';
import { RiskPillar } from '../../types';
import { ArrowUpRight, ArrowDownRight, Minus } from 'lucide-react';

interface RiskCardProps {
  pillar: RiskPillar;
}

const RiskCard: React.FC<RiskCardProps> = ({ pillar }) => {
  // Traffic Light Logic
  // High Score = High Risk = BAD (Red)
  let statusColor = 'text-emerald-500';
  let bgColor = 'bg-emerald-500/10';
  let borderColor = 'border-emerald-500/20';
  let progressColor = 'bg-emerald-500';

  if (pillar.score >= 75) {
    statusColor = 'text-red-500';
    bgColor = 'bg-red-500/10';
    borderColor = 'border-red-500/20';
    progressColor = 'bg-red-500';
  } else if (pillar.score >= 45) {
    statusColor = 'text-amber-500';
    bgColor = 'bg-amber-500/10';
    borderColor = 'border-amber-500/20';
    progressColor = 'bg-amber-500';
  }

  return (
    <div className={`relative p-5 rounded-lg border ${borderColor} ${bgColor} backdrop-blur-sm transition-all hover:shadow-lg hover:shadow-black/20`}>
      <div className="flex justify-between items-start mb-4">
        <div>
          <h3 className="text-slate-400 text-sm font-medium uppercase tracking-wider">{pillar.name}</h3>
          <div className="flex items-baseline mt-1 gap-2">
            <span className={`text-4xl font-bold ${statusColor}`}>{pillar.score}</span>
            <span className="text-slate-500 text-xs font-mono">/100</span>
          </div>
        </div>

        {/* Trend Indicator */}
        <div className={`flex items-center gap-1 text-xs font-medium px-2 py-1 rounded-full bg-slate-800/50 border border-slate-700 ${
          pillar.trend === 'up' ? 'text-red-400' : pillar.trend === 'down' ? 'text-emerald-400' : 'text-slate-400'
        }`}>
          {pillar.trend === 'up' && <ArrowUpRight className="w-3 h-3" />}
          {pillar.trend === 'down' && <ArrowDownRight className="w-3 h-3" />}
          {pillar.trend === 'stable' && <Minus className="w-3 h-3" />}
          {Math.abs(pillar.trendValue)}%
        </div>
      </div>

      {/* Progress Bar (Gauge equivalent) */}
      <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden mb-4">
        <div 
          className={`h-full rounded-full ${progressColor} transition-all duration-1000 ease-out`} 
          style={{ width: `${pillar.score}%` }}
        />
      </div>

      {/* Top Drivers */}
      <div>
        <h4 className="text-xs text-slate-500 uppercase font-semibold mb-2">Top Drivers</h4>
        <div className="space-y-2">
          {pillar.drivers.map((driver) => (
            <div key={driver.id} className="flex justify-between items-center text-sm">
              <span className="text-slate-300 truncate pr-2">{driver.name}</span>
              <div className="flex items-center gap-2">
                <div className="w-16 h-1 bg-slate-800 rounded-full overflow-hidden">
                   <div className="h-full bg-slate-500" style={{ width: `${driver.impact}%` }}></div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default RiskCard;

import React, { useState } from 'react';
import { CompanyData } from '../types';
import { Upload, FileText, Link as LinkIcon, ExternalLink, X, Plus } from 'lucide-react';

interface EvidencePanelProps {
  company: CompanyData;
}

const EvidencePanel: React.FC<EvidencePanelProps> = ({ company }) => {
  const [isDragOver, setIsDragOver] = useState(false);
  const [isUploading, setIsUploading] = useState(false);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(true);
  };

  const handleDragLeave = () => {
    setIsDragOver(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
    // Simulate upload
    setIsUploading(true);
    setTimeout(() => setIsUploading(false), 2000);
  };

  return (
    <div className="h-full flex flex-col">
      {/* Upload Zone - "Feed the Beast" */}
      <div 
        className={`
          relative border-2 border-dashed rounded-lg p-8 mb-6 text-center transition-all duration-200
          ${isDragOver ? 'border-indigo-500 bg-indigo-500/10' : 'border-slate-700 bg-slate-800/30'}
        `}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
      >
        {isUploading ? (
          <div className="flex flex-col items-center animate-pulse">
            <div className="w-12 h-12 rounded-full border-4 border-indigo-500 border-t-transparent animate-spin mb-3"></div>
            <p className="text-indigo-400 font-medium">Ingesting & Vectorizing...</p>
          </div>
        ) : (
          <div className="flex flex-col items-center">
            <div className="w-12 h-12 bg-slate-800 rounded-full flex items-center justify-center mb-3 text-indigo-400">
              <Upload className="w-6 h-6" />
            </div>
            <h3 className="text-slate-200 font-medium mb-1">Feed the Beast</h3>
            <p className="text-slate-500 text-sm mb-4 max-w-xs mx-auto">
              Drag & drop Annual Reports (PDF) or paste URLs here to update the risk model.
            </p>

            <div className="flex gap-2 w-full max-w-md">
                <input 
                    type="text" 
                    placeholder="Or paste URL here..." 
                    className="flex-1 bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm text-slate-200 focus:outline-none focus:border-indigo-500"
                />
                <button className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded text-sm font-medium transition-colors">
                    Ingest
                </button>
            </div>
          </div>
        )}
      </div>

      {/* Evidence List */}
      <div className="flex-1 overflow-hidden flex flex-col">
        <h3 className="text-slate-400 text-xs font-bold uppercase tracking-wider mb-3">Evidence Locker ({company.evidence.length})</h3>

        <div className="flex-1 overflow-y-auto pr-2 space-y-2">
          {company.evidence.map((item) => (
            <div key={item.id} className="group flex items-center justify-between p-3 rounded bg-slate-800/50 border border-slate-800 hover:border-slate-600 transition-all">
              <div className="flex items-start gap-3 overflow-hidden">
                <div className={`mt-1 w-8 h-8 rounded flex items-center justify-center shrink-0 ${
                  item.type === 'PDF' ? 'bg-red-500/20 text-red-400' :
                  item.type === 'URL' ? 'bg-blue-500/20 text-blue-400' :
                  'bg-amber-500/20 text-amber-400'
                }`}>
                  {item.type === 'PDF' && <FileText className="w-4 h-4" />}
                  {item.type === 'URL' && <LinkIcon className="w-4 h-4" />}
                  {item.type === 'NEWS' && <ExternalLink className="w-4 h-4" />}
                </div>

                <div className="min-w-0">
                  <p className="text-sm text-slate-200 font-medium truncate group-hover:text-indigo-300 transition-colors">
                    {item.name}
                  </p>
                  <div className="flex items-center gap-2 mt-1">
                    <span className="text-xs text-slate-500">{item.date}</span>
                    <div className="flex gap-1">
                        {item.tags.map(tag => (
                            <span key={tag} className="text-[10px] bg-slate-700 text-slate-300 px-1.5 py-0.5 rounded-full">{tag}</span>
                        ))}
                    </div>
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button className="text-slate-500 hover:text-slate-300 p-1">
                    <ExternalLink className="w-4 h-4" />
                </button>
                <button className="text-slate-500 hover:text-red-400 p-1">
                    <X className="w-4 h-4" />
                </button>
              </div>
            </div>
          ))}

          <button className="w-full py-3 border border-dashed border-slate-700 text-slate-500 rounded hover:border-slate-500 hover:text-slate-400 transition-colors flex items-center justify-center gap-2 text-sm">
            <Plus className="w-4 h-4" /> Add Historical Document
          </button>
        </div>
      </div>
    </div>
  );
};

export default EvidencePanel;

import React, { useState } from 'react';
import { CompanyData, Indicator } from '../types';
import { AlertCircle, CheckCircle2, Edit2, ShieldCheck, History } from 'lucide-react';

interface IndicatorTableProps {
  company: CompanyData;
}

const IndicatorTable: React.FC<IndicatorTableProps> = ({ company }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempValue, setTempValue] = useState<string | number>('');
  const [reason, setReason] = useState('');

  const handleEditClick = (indicator: Indicator) => {
    setEditingId(indicator.id);
    setTempValue(indicator.value);
    setReason(indicator.overrideReason || '');
  };

  const handleCancel = () => {
    setEditingId(null);
    setTempValue('');
    setReason('');
  };

  const handleSave = () => {
    // In a real app, this would dispatch an update to the backend
    console.log(`Updating ${editingId} to ${tempValue} because: ${reason}`);
    setEditingId(null);
  };

  return (
    <div className="overflow-x-auto">
      <table className="w-full text-left border-collapse">
        <thead>
          <tr className="border-b border-slate-700 text-xs text-slate-500 uppercase tracking-wider">
            <th className="py-3 px-4 font-semibold">Indicator</th>
            <th className="py-3 px-4 font-semibold">Value</th>
            <th className="py-3 px-4 font-semibold">Confidence</th>
            <th className="py-3 px-4 font-semibold">Source</th>
            <th className="py-3 px-4 font-semibold text-right">Last Updated</th>
            <th className="py-3 px-4 font-semibold w-16"></th>
          </tr>
        </thead>
        <tbody className="text-sm">
          {company.indicators.map((indicator) => (
            <React.Fragment key={indicator.id}>
              <tr className={`
                group border-b border-slate-800 transition-colors
                ${editingId === indicator.id ? 'bg-indigo-500/5' : 'hover:bg-slate-800/30'}
              `}>
                {/* Name */}
                <td className="py-3 px-4">
                  <div className="flex items-center gap-2">
                    <span className="text-slate-200 font-medium">{indicator.name}</span>
                    {indicator.isOverridden && (
                      <div className="group/tooltip relative">
                         <ShieldCheck className="w-4 h-4 text-amber-500 cursor-help" />
                         <div className="absolute left-0 bottom-6 w-48 bg-slate-900 border border-slate-700 p-2 rounded shadow-xl hidden group-hover/tooltip:block z-10">
                            <p className="text-xs text-slate-400">Manually Verified</p>
                            <p className="text-xs text-slate-500 italic mt-1">"{indicator.overrideReason}"</p>
                         </div>
                      </div>
                    )}
                  </div>
                </td>

                {/* Value (Editable) */}
                <td className="py-3 px-4">
                    {editingId === indicator.id ? (
                        <div className="flex items-center gap-2">
                            <input 
                                type="text" 
                                value={tempValue} 
                                onChange={(e) => setTempValue(e.target.value)}
                                className="w-24 bg-slate-900 border border-indigo-500 rounded px-2 py-1 text-slate-200 focus:outline-none"
                                autoFocus
                            />
                            <span className="text-slate-500 text-xs">{indicator.unit}</span>
                        </div>
                    ) : (
                        <span className={`font-mono ${indicator.isOverridden ? 'text-amber-400 font-bold' : 'text-slate-300'}`}>
                            {indicator.value} <span className="text-slate-500 text-xs">{indicator.unit}</span>
                        </span>
                    )}
                </td>

                {/* Confidence Badge */}
                <td className="py-3 px-4">
                  <div className="flex items-center gap-2">
                    <div className="w-16 h-1.5 bg-slate-800 rounded-full overflow-hidden">
                      <div 
                        className={`h-full rounded-full ${indicator.confidence > 90 ? 'bg-emerald-500' : indicator.confidence > 70 ? 'bg-amber-500' : 'bg-red-500'}`}
                        style={{ width: `${indicator.confidence}%` }}
                      ></div>
                    </div>
                    <span className="text-xs text-slate-500">{indicator.confidence}%</span>
                  </div>
                </td>

                {/* Source */}
                <td className="py-3 px-4">
                   <div className="flex items-center gap-1.5 text-slate-400">
                      <FileText className="w-3.5 h-3.5" />
                      <span className="truncate max-w-[150px]">{indicator.source}</span>
                   </div>
                </td>

                {/* Last Updated */}
                <td className="py-3 px-4 text-right text-slate-500 font-mono text-xs">
                    {indicator.lastUpdated}
                </td>

                {/* Actions */}
                <td className="py-3 px-4 text-right">
                    {editingId === indicator.id ? (
                        <div className="flex gap-1 justify-end">
                            {/* Save/Cancel handled in the expanded row, but shortcuts here */}
                        </div>
                    ) : (
                        <button 
                            onClick={() => handleEditClick(indicator)}
                            className="opacity-0 group-hover:opacity-100 p-1.5 hover:bg-slate-700 rounded text-slate-400 hover:text-indigo-400 transition-all"
                            title="Manual Override"
                        >
                            <Edit2 className="w-4 h-4" />
                        </button>
                    )}
                </td>
              </tr>

              {/* Expanded Edit Mode Row */}
              {editingId === indicator.id && (
                <tr className="bg-indigo-500/5 border-b border-indigo-500/30">
                    <td colSpan={6} className="p-4">
                        <div className="flex items-start gap-4">
                            <div className="flex-1">
                                <label className="block text-xs text-indigo-300 font-medium mb-1">Reason for Change (Required)</label>
                                <textarea 
                                    value={reason}
                                    onChange={(e) => setReason(e.target.value)}
                                    placeholder="Why are you overriding the AI model?"
                                    className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-sm text-slate-200 focus:border-indigo-500 focus:outline-none h-20 resize-none"
                                />
                            </div>
                            <div className="flex flex-col gap-2 pt-5">
                                <button 
                                    onClick={handleSave}
                                    disabled={!reason || !tempValue}
                                    className="px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded text-sm font-medium disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                                >
                                    <CheckCircle2 className="w-4 h-4" /> Save Override
                                </button>
                                <button 
                                    onClick={handleCancel}
                                    className="px-4 py-2 bg-transparent border border-slate-700 hover:bg-slate-800 text-slate-300 rounded text-sm font-medium"
                                >
                                    Cancel
                                </button>
                            </div>
                        </div>
                        <div className="mt-3 flex items-center gap-2 text-xs text-slate-500">
                            <AlertCircle className="w-3.5 h-3.5" />
                            <span>Overriding locks this value. The AI will no longer update it automatically.</span>
                        </div>
                    </td>
                </tr>
              )}
            </React.Fragment>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default IndicatorTable;

