import React, { useState } from 'react';
import { 
  Save, 
  AlertTriangle, 
  Shield, 
  Globe, 
  Trash2, 
  Plus, 
  Ban, 
  CheckCircle, 
  RefreshCw,
  Sliders,
  Info
} from 'lucide-react';

interface DriverWeight {
  id: string;
  name: string;
  category: 'Sustainability' | 'PCHI' | 'Operational' | 'Financial';
  weight: number;
}

interface DomainRule {
  id: string;
  domain: string;
  type: 'BLACKLIST' | 'WHITELIST';
  addedBy: string;
  date: string;
}

const RiskConfiguration: React.FC = () => {
  // --- State: Weights ---
  const [weights, setWeights] = useState<DriverWeight[]>([
    { id: 'w1', name: 'Carbon Emissions (Scope 1 & 2)', category: 'Sustainability', weight: 20 },
    { id: 'w2', name: 'Physical Climate Risk (Heat/Flood)', category: 'PCHI', weight: 25 },
    { id: 'w3', name: 'Supply Chain Stability', category: 'Operational', weight: 15 },
    { id: 'w4', name: 'Liquidity & Solvency', category: 'Financial', weight: 20 },
    { id: 'w5', name: 'Labor Practices & Human Rights', category: 'Operational', weight: 10 },
    { id: 'w6', name: 'Corporate Governance', category: 'Sustainability', weight: 10 },
  ]);

  const totalWeight = weights.reduce((sum, w) => sum + w.weight, 0);

  const handleWeightChange = (id: string, newValue: number) => {
    setWeights(weights.map(w => w.id === id ? { ...w, weight: newValue } : w));
  };

  // --- State: Thresholds ---
  const [thresholds, setThresholds] = useState({
    medium: 45, // Scores above this are Medium
    high: 75    // Scores above this are High
  });

  // --- State: Sources ---
  const [domains, setDomains] = useState<DomainRule[]>([
    { id: 'd1', domain: 'fakenews.com', type: 'BLACKLIST', addedBy: 'Admin', date: '2024-01-15' },
    { id: 'd2', domain: 'reuters.com', type: 'WHITELIST', addedBy: 'System', date: '2023-11-20' },
  ]);
  const [newDomain, setNewDomain] = useState('');

  const handleAddDomain = (type: 'BLACKLIST' | 'WHITELIST') => {
    if (!newDomain) return;
    setDomains([...domains, {
      id: `d-${Date.now()}`,
      domain: newDomain,
      type,
      addedBy: 'You',
      date: new Date().toLocaleDateString()
    }]);
    setNewDomain('');
  };

  const removeDomain = (id: string) => {
    setDomains(domains.filter(d => d.id !== id));
  };

  return (
    <div className="flex-1 overflow-y-auto bg-slate-900">
      {/* Header */}
      <div className="px-8 py-6 border-b border-slate-800 bg-slate-900/80 backdrop-blur sticky top-0 z-10">
        <div className="flex justify-between items-center">
            <div>
                <h1 className="text-2xl font-bold text-white tracking-tight flex items-center gap-2">
                    <Sliders className="w-6 h-6 text-indigo-500" />
                    Global Risk Configuration
                </h1>
                <p className="text-slate-500 text-sm mt-1">Configure scoring algorithms, risk thresholds, and trusted intelligence sources.</p>
            </div>
            <button className="bg-indigo-600 hover:bg-indigo-500 text-white px-5 py-2.5 rounded-lg text-sm font-medium flex items-center gap-2 shadow-lg shadow-indigo-500/20 transition-all">
                <Save className="w-4 h-4" /> Save Changes
            </button>
        </div>
      </div>

      <div className="p-8 max-w-6xl mx-auto space-y-8">

        {/* Section 1: Model Weights */}
        <section className="bg-slate-900 border border-slate-800 rounded-xl p-6 shadow-xl">
            <div className="flex justify-between items-start mb-6">
                <div>
                    <h2 className="text-lg font-semibold text-white">Algorithm Weights</h2>
                    <p className="text-sm text-slate-500">Adjust the influence of each risk driver on the global company score.</p>
                </div>
                <div className={`px-4 py-2 rounded-lg font-mono text-sm font-bold border ${totalWeight === 100 ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 'bg-red-500/10 text-red-400 border-red-500/20'}`}>
                    Total: {totalWeight}%
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-6">
                {weights.map((driver) => (
                    <div key={driver.id} className="space-y-2">
                        <div className="flex justify-between text-sm">
                            <span className="text-slate-200 font-medium">{driver.name}</span>
                            <span className="text-slate-400">{driver.weight}%</span>
                        </div>
                        <div className="flex items-center gap-4">
                            <input 
                                type="range" 
                                min="0" 
                                max="100" 
                                step="5"
                                value={driver.weight}
                                onChange={(e) => handleWeightChange(driver.id, parseInt(e.target.value))}
                                className="flex-1 h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500"
                            />
                            <div className="w-12 text-right">
                                <span className={`text-xs px-1.5 py-0.5 rounded border ${
                                    driver.category === 'Sustainability' ? 'border-emerald-500/30 text-emerald-400' :
                                    driver.category === 'PCHI' ? 'border-blue-500/30 text-blue-400' :
                                    driver.category === 'Operational' ? 'border-amber-500/30 text-amber-400' :
                                    'border-purple-500/30 text-purple-400'
                                }`}>
                                    {driver.category.substring(0, 3).toUpperCase()}
                                </span>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            {totalWeight !== 100 && (
                <div className="mt-6 flex items-center gap-2 text-red-400 text-sm bg-red-500/10 p-3 rounded border border-red-500/20">
                    <AlertTriangle className="w-4 h-4" />
                    Warning: Total weight must equal 100% for the scoring model to be valid.
                </div>
            )}
        </section>

        {/* Section 2: Thresholds */}
        <section className="bg-slate-900 border border-slate-800 rounded-xl p-6 shadow-xl">
            <div className="mb-6">
                <h2 className="text-lg font-semibold text-white">Risk Thresholds</h2>
                <p className="text-sm text-slate-500">Define the score boundaries that trigger risk alerts.</p>
            </div>

            <div className="relative pt-6 pb-2 px-4">
                {/* Gradient Bar */}
                <div className="h-4 w-full rounded-full bg-gradient-to-r from-emerald-500 via-amber-500 to-red-500 relative">
                    {/* Markers */}
                    <div 
                        className="absolute top-1/2 -translate-y-1/2 w-1 h-8 bg-white border-2 border-slate-900 cursor-ew-resize shadow-lg z-10"
                        style={{ left: `${thresholds.medium}%` }}
                    ></div>
                     <div 
                        className="absolute top-1/2 -translate-y-1/2 w-1 h-8 bg-white border-2 border-slate-900 cursor-ew-resize shadow-lg z-10"
                        style={{ left: `${thresholds.high}%` }}
                    ></div>
                </div>

                <div className="flex justify-between mt-6 text-center">
                    <div className="flex-1">
                        <div className="text-emerald-500 font-bold text-lg">&lt; {thresholds.medium}</div>
                        <div className="text-xs text-slate-500 uppercase tracking-wide">Low Risk (Green)</div>
                    </div>
                    <div className="flex-1 border-x border-slate-800">
                        <div className="text-amber-500 font-bold text-lg">{thresholds.medium} - {thresholds.high}</div>
                        <div className="text-xs text-slate-500 uppercase tracking-wide">Medium Risk (Amber)</div>
                    </div>
                    <div className="flex-1">
                        <div className="text-red-500 font-bold text-lg">&gt; {thresholds.high}</div>
                        <div className="text-xs text-slate-500 uppercase tracking-wide">High Risk (Red)</div>
                    </div>
                </div>

                <div className="mt-6 grid grid-cols-2 gap-4 max-w-md mx-auto">
                    <div>
                         <label className="block text-xs text-slate-500 mb-1">Amber Threshold</label>
                         <input 
                            type="number" 
                            value={thresholds.medium}
                            onChange={(e) => setThresholds({...thresholds, medium: parseInt(e.target.value)})}
                            className="w-full bg-slate-800 border border-slate-700 rounded px-3 py-2 text-white focus:outline-none focus:border-indigo-500"
                         />
                    </div>
                    <div>
                         <label className="block text-xs text-slate-500 mb-1">Red Threshold</label>
                         <input 
                            type="number" 
                            value={thresholds.high}
                            onChange={(e) => setThresholds({...thresholds, high: parseInt(e.target.value)})}
                            className="w-full bg-slate-800 border border-slate-700 rounded px-3 py-2 text-white focus:outline-none focus:border-indigo-500"
                         />
                    </div>
                </div>
            </div>
        </section>

        {/* Section 3: Source Management */}
        <section className="bg-slate-900 border border-slate-800 rounded-xl p-6 shadow-xl">
             <div className="mb-6">
                <h2 className="text-lg font-semibold text-white flex items-center gap-2">
                    <Shield className="w-5 h-5 text-indigo-400" />
                    Source Intelligence
                </h2>
                <p className="text-sm text-slate-500">Manage whitelisted (trusted) and blacklisted (ignored) domains for the scraper.</p>
            </div>

            <div className="flex gap-2 mb-6">
                <div className="relative flex-1">
                    <Globe className="absolute left-3 top-2.5 w-4 h-4 text-slate-500" />
                    <input 
                        type="text" 
                        placeholder="Enter domain (e.g., propaganda.com)..." 
                        value={newDomain}
                        onChange={(e) => setNewDomain(e.target.value)}
                        className="w-full bg-slate-800 border border-slate-700 rounded-lg pl-9 pr-4 py-2 text-sm text-white focus:border-indigo-500 focus:outline-none"
                    />
                </div>
                <button 
                    onClick={() => handleAddDomain('BLACKLIST')}
                    className="px-4 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors"
                >
                    <Ban className="w-4 h-4" /> Block
                </button>
                <button 
                    onClick={() => handleAddDomain('WHITELIST')}
                    className="px-4 py-2 bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 border border-emerald-500/20 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors"
                >
                    <CheckCircle className="w-4 h-4" /> Trust
                </button>
            </div>

            <div className="overflow-hidden rounded-lg border border-slate-800">
                <table className="w-full text-left text-sm">
                    <thead className="bg-slate-950 text-slate-500 font-medium border-b border-slate-800">
                        <tr>
                            <th className="px-4 py-3">Domain</th>
                            <th className="px-4 py-3">Status</th>
                            <th className="px-4 py-3">Added By</th>
                            <th className="px-4 py-3 text-right">Action</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-800 bg-slate-900/50">
                        {domains.map((rule) => (
                            <tr key={rule.id} className="group hover:bg-slate-800/50 transition-colors">
                                <td className="px-4 py-3 font-medium text-slate-300">{rule.domain}</td>
                                <td className="px-4 py-3">
                                    <span className={`inline-flex items-center gap-1.5 px-2 py-0.5 rounded text-xs font-medium border ${
                                        rule.type === 'BLACKLIST' 
                                        ? 'bg-red-500/10 text-red-400 border-red-500/20' 
                                        : 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'
                                    }`}>
                                        {rule.type === 'BLACKLIST' ? <Ban className="w-3 h-3" /> : <CheckCircle className="w-3 h-3" />}
                                        {rule.type}
                                    </span>
                                </td>
                                <td className="px-4 py-3 text-slate-500">
                                    <span className="text-xs">{rule.addedBy} • {rule.date}</span>
                                </td>
                                <td className="px-4 py-3 text-right">
                                    <button 
                                        onClick={() => removeDomain(rule.id)}
                                        className="text-slate-600 hover:text-red-400 transition-colors"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                {domains.length === 0 && (
                    <div className="p-8 text-center text-slate-500 text-sm">No domain rules configured.</div>
                )}
            </div>
        </section>

      </div>
    </div>
  );
};

export default RiskConfiguration;

import React, { useState } from 'react';
import { 
  LayoutDashboard, 
  Building2, 
  Settings, 
  LogOut
} from 'lucide-react';
import MasterUniverse from './components/MasterUniverse';
import CompanyDetail from './components/CompanyDetail';
import RiskConfiguration from './components/RiskConfiguration';

type ViewMode = 'DASHBOARD' | 'COMPANY_DETAIL' | 'SETTINGS';

export default function App() {
  const [currentView, setCurrentView] = useState<ViewMode>('DASHBOARD');
  // In a real app, this would be an ID we fetch
  const [selectedCompanyId, setSelectedCompanyId] = useState<string | null>(null);

  const navigateToCompany = (id: string) => {
    setSelectedCompanyId(id);
    setCurrentView('COMPANY_DETAIL');
  };

  const navigateToDashboard = () => {
    setCurrentView('DASHBOARD');
    setSelectedCompanyId(null);
  };

  const navigateToSettings = () => {
    setCurrentView('SETTINGS');
    setSelectedCompanyId(null);
  };

  return (
    <div className="flex h-screen overflow-hidden bg-slate-900 text-slate-200 font-sans selection:bg-indigo-500/30">

      {/* Sidebar - Global Navigation */}
      <aside className="w-16 flex flex-col items-center py-6 border-r border-slate-800 bg-slate-950/50 backdrop-blur-sm z-20">
        <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center mb-8 shadow-lg shadow-indigo-500/20 cursor-pointer" onClick={navigateToDashboard}>
          <span className="font-bold text-lg">R</span>
        </div>

        <nav className="flex-1 flex flex-col gap-6">
          <SidebarIcon 
             icon={<LayoutDashboard />} 
             label="Dashboard" 
             active={currentView === 'DASHBOARD'} 
             onClick={navigateToDashboard}
          />
          <SidebarIcon 
             icon={<Building2 />} 
             label="Companies" 
             active={currentView === 'COMPANY_DETAIL'} 
             // Logic to just go back to company list if clicked
             onClick={navigateToDashboard}
          />
          <SidebarIcon 
             icon={<Settings />} 
             label="Settings" 
             active={currentView === 'SETTINGS'} 
             onClick={navigateToSettings}
          />
        </nav>

        <div className="mt-auto">
          <SidebarIcon icon={<LogOut />} label="Logout" />
        </div>
      </aside>

      {/* Main Content Area - Swaps based on View */}
      <main className="flex-1 h-full overflow-hidden relative flex flex-col">
          {currentView === 'DASHBOARD' ? (
              <MasterUniverse onNavigateToCompany={navigateToCompany} />
          ) : currentView === 'COMPANY_DETAIL' ? (
              <CompanyDetail onBack={navigateToDashboard} />
          ) : (
              <RiskConfiguration />
          )}
      </main>
    </div>
  );
}

// Helper for Sidebar Icons
interface SidebarIconProps {
    icon: React.ReactNode;
    label: string;
    active?: boolean;
    onClick?: () => void;
}

const SidebarIcon = ({ icon, label, active = false, onClick }: SidebarIconProps) => (
  <button 
    onClick={onClick}
    className={`
      p-3 rounded-xl transition-all group relative
      ${active ? 'bg-indigo-500/10 text-indigo-400' : 'text-slate-500 hover:bg-slate-800 hover:text-slate-300'}
    `}
  >
    {icon}
    {/* Tooltip */}
    <span className="absolute left-14 bg-slate-800 text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap border border-slate-700 pointer-events-none z-50 shadow-lg">
      {label}
    </span>
  </button>
);
